request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?next1 ?next1Name ?next1Type ?next2 ?next2Name ?next2Type ?next3 ?next3Name ?next3Type WHERE {
  VALUES ?source { <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-5FBF062E-34D8-41B6-BFC9-960AD9ABA3A6> }

  # First hop from Produktstart erfragen
  ?e1 a bbo:SequenceFlow .
  ?e1 bbo:has_sourceRef ?source .
  ?e1 bbo:has_targetRef ?next1 .
  ?next1 a ?next1Type .
  OPTIONAL { ?next1 bbo:name ?next1Name . }

  # Second hop
  OPTIONAL {
    ?e2 a bbo:SequenceFlow .
    ?e2 bbo:has_sourceRef ?next1 .
    ?e2 bbo:has_targetRef ?next2 .
    ?next2 a ?next2Type .
    OPTIONAL { ?next2 bbo:name ?next2Name . }

    # Third hop
    OPTIONAL {
      ?e3 a bbo:SequenceFlow .
      ?e3 bbo:has_sourceRef ?next2 .
      ?e3 bbo:has_targetRef ?next3 .
      ?next3 a ?next3Type .
      OPTIONAL { ?next3 bbo:name ?next3Name . }
    }
  }
}
LIMIT 25
